var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 부르자, 약속한 장소에서 기다리고 있겠다는 대답이 돌아왔다.","JPN":"意を決して彼女を呼び出すと、約束の場所で待っているとの返事が返ってきた。","ENG":"Having decided that, you called her. She answered she'd be waiting for you at the place you promised to meet.","TWN":"做好心理準備後呼喚她，收到回覆說在約定的地點等待中。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"여기 계셨군요, 주인님.","JPN":"ここにいらしたのですね、ご主人様。","ENG":"You're here, Master.","TWN":"主人，原來您在這裡！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"식장에 얼씬거리던 참새들을 쫓아내고 오는 길입니다.","JPN":"式場をウロウロしていたスズメたちを追い払ってきたところです。","ENG":"I was out driving away potential wedding crashers.","TWN":"我在會場趕走討人厭的麻雀後過來的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"이걸로, 주인님의 눈엣가시들은 거의 처리한 것 같군요.","JPN":"これでご主人様の邪魔者はほぼ処理できたようですね。","ENG":"This should have taken care of most of the thorns in your side.","TWN":"這樣，那些主人眼中釘應該都清乾淨了吧？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"결례라는 건 알지만, 잠시 주인님 곁에서 한숨 돌려도 괜찮을까요?","JPN":"失礼であることは承知の上ですが、しばしご主人様の隣で休んでもよろしいでしょうか？","ENG":"Mind if I sit by yourself and take a breather?","TWN":"真是不好意思，請問可以在主人身邊稍微喘口氣嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"……","JPN":"……","ENG":"……","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"네, 정말 기분 좋은 고요함이군요.","JPN":"はい、とても心地よい静けさですね。","ENG":"Yes, I love peace and quiet.","TWN":"是的，真是令人神清氣爽的寧靜感。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"제 업무가 만족스러우셨다니 다행입니다.","JPN":"私の仕事ぶりにご満足いただけたようで幸いです。","ENG":"I'm glad you're satisfied by my performance.","TWN":"幸好主人對於我的任務是滿意的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"주인님도 제 심장소리가 들리시나요?","JPN":"ご主人様にも私の鼓動が聞こえますか？","ENG":"Can you hear my heartbeat?","TWN":"主人也有聽到我的心跳聲嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"저는 지쳐 쓰러질 줄도, 부끄러워할 줄도 모르는 몸이기에, 이 심장소리에 귀 기울이며 제 자신의 상태를 가늠하곤 한답니다.","JPN":"私は疲れて倒れることも、恥ずかしがることもできない身体ですので、この心臓の音に耳を澄まして自分自身の状態を確認します。","ENG":"Because I don't know when I'm tired or emotional, I always keep my ears to my heart's rhythm to measure my condition.","TWN":"因為我的身體不會感到疲憊，也不會感到害羞，所以通常都是根據心跳聲，來判斷我目前的狀態。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"그리고 주인님께서 절 바라보시는 지금은…… 좀처럼 차분해지지 못하고 있군요.","JPN":"そしてご主人様に見つめられている今は……なかなか心が落ち着きません。","ENG":"And now that you're staring at me... it's beating erratically.","TWN":"然後主人您現在這樣盯著人家看……害人家都靜不下來呢。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"하지만 괜찮습니다. 이럴 땐 메이드의 본분에 집중하는 것이 도움이 되곤 했죠.","JPN":"しかし大丈夫です。このような時はメイドの本分に集中することで巍然とした態度を保てるので。","ENG":"But don't worry. It usually calms down when I focus on my duty.","TWN":"但是沒關係！通常這種時候，只要專注在我身為女僕的本份上沒問題了！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"지금 제게 맡겨진 업무는 결혼식의 신부로 위장하여 주인님을 훼방꾼들로부터 지켜내는 것.","JPN":"今私に任された任務は、結婚式の花嫁役を演じて、ご主人様を邪魔者から守ること。","ENG":"Right now, my duty is to act as your bride and protect you against your enemies.","TWN":"我現在收到的任務是要偽裝成婚禮上的新娘，保護主人不受到干擾。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"누군가 아직 이곳 어딘가에 숨어 주인님의 행복을 방해하려 하고 있을지도 모릅니다.","JPN":"まだ何者かがどこかに隠れて、ご主人様の幸せを邪魔しようとしているかもしれません。","ENG":"Some of them still can be here somewhere, hiding, waiting to destroy your happiness.","TWN":"現在說不定某個人正躲在某個地方，想要妨礙主人的幸福呢！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"그러니 지금은, 행복한 신부의 역할에 계속 전념하는 것이 옳은 판단이겠죠.","JPN":"だから今は、幸せな花嫁役に専念し続けるのが正しい判断でしょう。","ENG":"So, for now, I should focus on playing the role of a happy bride.","TWN":"所以我現在最好還是專心扮演好幸福新娘的角色，這樣才是上上之策對吧！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"주인님?","JPN":"ご主人様？","ENG":"Master?","TWN":"主人？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"저 베로니카, 이렇게 무릎을 꿇고 신랑에게 청혼하겠습니다.","JPN":"私ベロニカ、このとおり跪いて新郎にプロポーズする次第です。","ENG":"I, Veronica, propose you on one knee.","TWN":"我貝洛妮卡要下跪向新郎求婚。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEADER_FLORA_WEDDING_NULL","text":{"KOREA":"이 반지를 받아주시겠어요?","JPN":"この指輪を受け取っていただけますか？","ENG":"Will you do me the honor of accepting this ring?","TWN":"您願意收下這枚戒指嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_FLORA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};